sql:
SELECT COUNT(*) 
FROM athletes 
WHERE weight > (SELECT AVG(weight) FROM athletes);

SELECT name 
FROM athletes 
WHERE coach_id = 0;

SELECT *
FROM athletes
WHERE athlete_id = coach_id;

SELECT name, state
FROM athletes
WHERE coach_id > 0;

external_knowledge:
- "guiding stars from Manitoba" refers to coaches from the state of Manitoba ('MB');
- "claimed on the podium" refers to their placement in the competition;
- "from the champions down to the contenders" means ordered from the best placement to the worst placement.
